/// Represents a task with an ID, title, completion status, optional due date, and tags.
#[derive(Debug, Clone)]
pub struct Task {
    pub id: u32,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Utc>>,
    pub tags: Vec<String>,
}

/// Manages a collection of tasks, allowing addition, completion, and retrieval of overdue tasks.
#[derive(Debug)]
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u32,
}

impl TaskManager {
    /// Creates a new TaskManager with an empty task list and ID starting at 1.
    pub fn new() -> Self {
        TaskManager {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a new task with the given title, optional due date, and tags.
    /// Returns the created Task or an error if the title is empty.
    pub fn add_task(
        &mut self,
        title: String,
        due_date: Option<DateTime<Utc>>,
        tags: Vec<String>,
    ) -> Result<Task, TaskError> {
        if title.trim().is_empty() {
            return Err(TaskError::new("Task title cannot be empty"));
        }
        let task = Task {
            id: self.next_id,
            title,
            completed: false,
            due_date,
            tags,
        };
        self.tasks.push(task.clone());
        self.next_id += 1;
        Ok(task)
    }

    /// Marks the task with the given ID as completed.
    /// Returns true if the task was found and updated, false otherwise.
    pub fn complete_task(&mut self, task_id: u32) -> bool {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == task_id) {
            task.completed = true;
            true
        } else {
            false
        }
    }

    /// Retrieves a list of overdue tasks (due date in the past and not completed).
    pub fn get_overdue(&self) -> Vec<Task> {
        let now = Utc::now();
        self.tasks
            .iter()
            .filter(|t| {
                t.due_date.map_or(false, |due| due < now && !t.completed)
            })
            .cloned()
            .collect()
    }
}

